import{_ as a,o as i,c as o,ae as t}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Apple Universal Links","description":"","frontmatter":{"title":"Apple Universal Links","slug":"ios-universal-links"},"headers":[],"relativePath":"developer-hub/ios-universal-links.md","filePath":"developer-hub/ios-universal-links.md"}'),n={name:"developer-hub/ios-universal-links.md"};function s(r,e,l,p,d,h){return i(),o("div",null,[...e[0]||(e[0]=[t('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch makes using Universal Links simple while simultaneously improving on them by offering full attribution and supporting edge cases where Universal Links fail. This allows you to deep link, even when the user doesn&#39;t have your app installed.</p><p><em>[Image: 1264]</em></p><h2 id="set-up-universal-links" tabindex="-1">Set Up Universal Links <a class="header-anchor" href="#set-up-universal-links" aria-label="Permalink to &quot;Set Up Universal Links&quot;">​</a></h2><ol><li><p>To get started, you’ll need to enable Universal Links on the Branch Dashboard. To do this:<br> a. Navigate to <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">App Settings</a> page in the Branch Dashboard.<br> b. Check the box to <strong>Enable Universal Links</strong> from iOS redirects.<br> c. Type in your App’s Bundle Identifier. Learn more <a href="./ios-basic-integration.html#2-configure-bundle-identifier">here</a>.<br> d. Type in your Apple App Prefix (found by clicking your app on <a href="https://developer.apple.com/account/ios/identifier/bundle" target="_blank" rel="noreferrer">this page</a> in Apple&#39;s Developer Portal).<br> e. Scroll down and click on the <strong>Save</strong> button.</p></li><li><p>From here, you’ll enable Associated Domains in Xcode. To do this:<br> a. Go to the <strong>Capabilities</strong> tab of your project file.<br> b. Scroll down and enable <strong>Associated Domains</strong>.<br> c. If you see an error after this step, please check that:</p><ol><li>The right team is selected for your Xcode project.</li><li>The Bundle Identifier of your Xcode project matches the one used to register the App Identifier with Apple.</li></ol></li><li><p>To add your Branch Link Domains:<br> a. On the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">App Settings</a> page, find the Link Domain section.<br> b. Copy your domain name.<br> c. In the Domains section, click the <strong>+ icon</strong> and add the following entries: (making sure that <code>xxxx</code> matches the subdomain prefix you&#39;ve been assigned or selected for yourself):</p><ul><li><code>applinks:xxxx.app.link</code></li><li><code>applinks:xxxx-alternate.app.link</code></li><li><code>applinks:xxxx.test-app.link</code></li><li><code>applinks:xxxx-alternate.test-app.link</code></li></ul></li></ol><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>If the Default domain name box shows the <strong>legacy</strong> <code>bnc.lt</code> <strong>domain</strong>, you should use the following entry instead: <code>applinks:bnc.lt</code></p></div><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>If you use a <strong>custom domain or subdomain</strong> for your Branch Links, you should instead add entries for <code>applinks:[mycustomdomainorsubdomain]</code>, <code>XXXX.app.link</code> and <code>XXXX-alternate.app.link</code>. If you&#39;re unsure of your Branch-assigned <code>app.link</code> subdomain, contact our <a href="./submit-a-ticket.html">support team</a> and we can provide it.</p></div><h2 id="app-and-browser-universal-links-support" tabindex="-1">App and browser Universal Links support <a class="header-anchor" href="#app-and-browser-universal-links-support" aria-label="Permalink to &quot;App and browser Universal Links support&quot;">​</a></h2><p>Please note that Universal Links don&#39;t work everywhere. We have compiled here the Universal Links support status of some popular apps.</p><h2 id="apps-that-always-work" tabindex="-1">Apps that always work <a class="header-anchor" href="#apps-that-always-work" aria-label="Permalink to &quot;Apps that always work&quot;">​</a></h2><p>If you open a Universal Link in one of these apps, it should work correctly all the time:</p><ul><li>Messages</li><li>Mail</li><li>WhatsApp</li><li>Gmail</li><li>Inbox</li></ul><h2 id="apps-limited-by-apple" tabindex="-1">Apps limited by Apple <a class="header-anchor" href="#apps-limited-by-apple" aria-label="Permalink to &quot;Apps limited by Apple&quot;">​</a></h2><p>Apple has limited Universal Links in certain situations:</p><ul><li>Universal Links will not work if you paste the link into the browser URL field.</li><li>Universal Links will not work with a user-driven <code>&lt;a href=&quot;...&quot;&gt;</code> element click on the same domain. For example, if there is a Universal Link on google.com pointing to a different Universal Link on google.com, it will not open the app.</li><li>Universal Links cannot be triggered via Javascript (in <code>window.onload</code> or via a <code>.click()</code> call on an <code>&lt;a&gt;</code> element) unless it is part of a user action.</li></ul><p>Apps/Browsers that work conditionally:</p><ul><li>Safari</li><li>Chrome</li></ul><h2 id="apps-that-work-sometimes" tabindex="-1">Apps that work sometimes <a class="header-anchor" href="#apps-that-work-sometimes" aria-label="Permalink to &quot;Apps that work sometimes&quot;">​</a></h2><p>Apps with built-in webviews (Google, Twitter, Facebook, Facebook Messenger, WeChat, etc.) work with Universal Links only when a webview is already open. In other words, Universal Links do not work in-app from the feed or main app views.<br> To work around this limitation, your links must have <a href="./deepviews.html">Deepviews</a> or something similar enabled, with a call-to-action link or button with a Universal Link behind it. This way, clicking a link from the app feed will open a webview containing your Deepview page, and the user can then click the link/button to launch your app. All of Apple&#39;s limitations (in the section above) still apply for the Deepview page.</p><p>Apps/Browsers that work conditionally:</p><ul><li>Google</li><li>Facebook</li><li>Facebook Messenger</li><li>WeChat</li><li>Twitter</li><li>LinkedIn</li><li>Any app using <code>SFSafariViewController</code></li></ul><h2 id="apps-with-special-cases" tabindex="-1">Apps with special cases <a class="header-anchor" href="#apps-with-special-cases" aria-label="Permalink to &quot;Apps with special cases&quot;">​</a></h2><p>Slack works if configured to open links in Safari. Otherwise, it works conditionally as in the above section.</p><h2 id="apps-that-do-not-work" tabindex="-1">Apps that do not work <a class="header-anchor" href="#apps-that-do-not-work" aria-label="Permalink to &quot;Apps that do not work&quot;">​</a></h2><ul><li>Instagram</li><li>Pinterest</li><li>Telegram</li></ul><h2 id="common-issues" tabindex="-1">Common issues <a class="header-anchor" href="#common-issues" aria-label="Permalink to &quot;Common issues&quot;">​</a></h2><p>If you are running into issues with Universal Links, please consider the questions below:</p><details><summary>Are you testing by manually entering into Safari?</summary><p>Universal Links don&#39;t work properly when entered into Safari. Use Notes or iMessage for testing.</p></details><details><summary>Are you wrapping Branch Links with another link and redirecting?</summary><p>In most cases, Universal Links won&#39;t open the app when they are &quot;wrapped&quot; by click tracking links. Universal links, including Branch Links, must be freestanding. If you want Universal Links to work in all situations, do not use other links that redirect to your Branch Links.</p></details><details><summary>Do your Team ID &amp; Bundle ID match those on your dashboard?</summary><p>You can find them in the Dashboard on the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">App Settings page</a>, in the iOS section next to &quot;Enable Universal Links.&quot; They should match your Team ID and Bundle ID. Team ID can be found <a href="https://developer.apple.com/membercenter/index.action#accountSummary" target="_blank" rel="noreferrer">here</a>. Your Bundle ID is found in Xcode, in the <strong>General</strong> tab for the correct build target. If your Apple App Prefix is different from your Team ID, you should use your App Prefix. Your App Prefix can be found from App IDs on Apple&#39;s Developer Portal.</p></details><details><summary>Have you deleted the app and reinstalled it?</summary><p>iOS does not re-scrape the Apple-app-site-association file unless you delete and reinstall the app. (The only exception to this is App Store updates. iOS does rescrape on every update. This means that when users update to a version of your app with the Applinks entitlement, Universal Links will start working for them.)</p></details><details><summary>Universal Links can be disabled</summary><p>If you are successfully taken into your app via a Universal Link, you&#39;ll see &quot;app.link&quot; (or your domain) and a forward button in the top right corner of the status bar. If you click that button, Apple will no longer activate Universal Links in the future. To re-enable Universal Links, long press on the link in Messages (iOS 9 only due to iMessage revamp in 10) or Notes (iOS 10/9) and choose &#39;Open in APP&#39;.</p></details><details><summary>Are you using a custom domain?</summary><p>Make sure it&#39;s configured correctly. The following error message will appear in your OS-level logs if your domain doesn&#39;t have SSL set up properly:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sep 21 14:27:01 Derricks-iPhone swcd[2044] : 2015-09-21 02:27:01.878907 PM [SWC] ### Rejecting URL &#39;https://examplecustomdomain.com/apple-app-site-association&#39; for auth method &#39;NSURLAuthenticationMethodServerTrust&#39;: -6754/0xFFFFE59E kAuthenticationErr</span></span></code></pre></div><p>These logs can be found for physical devices connected to Xcode by navigating to Window &gt; Devices &gt; choosing your device and then clicking the &quot;up&quot; arrow in the bottom left corner of the main view.</p><p>If you&#39;re using a custom subdomain, your CNAME should point to <code>custom.bnc.lt</code> under <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">Configuration</a> in the Branch Dashboard.</p></details>',33)])])}const m=a(n,[["render",s]]);export{u as __pageData,m as default};
